### Step 2: Implement buffered mode in handleTextDelta

Update `handleTextDelta` to accept a `streaming` parameter and short-circuit accumulation when `streaming === false`:

```typescript
async function handleTextDelta(
  channelId: string,
  textChunk: string,
  threadTs: string | undefined,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: AdapterOutboundCallbacks,
  startTime: number,
  streaming: boolean,
): Promise<DeliveryResult> {
  const key = streamKey(channelId, threadTs);
  const existing = streamState.get(key);

  // Buffered mode: accumulate text without posting or updating
  if (!streaming) {
    if (existing) {
      existing.accumulatedText += textChunk;
    } else {
      streamState.set(key, {
        streamId: randomUUID(),
        channelId,
        threadTs: threadTs ?? '',
        messageTs: '',  // No message posted yet
        accumulatedText: textChunk,
        lastUpdateAt: 0,
        startedAt: Date.now(),
      });
    }
    return { success: true, durationMs: Date.now() - startTime };
  }

  // ... existing streaming mode logic (unchanged) ...
}
```

The key difference: in buffered mode, `messageTs` is set to `''` (empty string) to indicate no Slack message has been posted yet.

### Step 3: Update handleDone for buffered mode

Update `handleDone` to detect buffered mode (empty `messageTs`) and send via `chat.postMessage` instead of `chat.update`:

```typescript
async function handleDone(
  channelId: string,
  threadTs: string | undefined,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: AdapterOutboundCallbacks,
  startTime: number,
): Promise<DeliveryResult> {
  const key = streamKey(channelId, threadTs);
  const existing = streamState.get(key);
  streamState.delete(key);

  if (!existing) {
    return { success: true, durationMs: Date.now() - startTime };
  }

  // Buffered mode: post accumulated text as a new message
  if (!existing.messageTs) {
    return wrapSlackCall(
      () => client.chat.postMessage({
        channel: channelId,
        text: truncateText(formatForPlatform(existing.accumulatedText, 'slack'), MAX_MESSAGE_LENGTH),
        ...(threadTs ? { thread_ts: threadTs } : {}),
      }),
      callbacks,
      startTime,
      true,
    );
  }

  // Streaming mode: update existing message
  return wrapSlackCall(
    () => client.chat.update({
      channel: channelId,
      ts: existing.messageTs,
      text: truncateText(formatForPlatform(existing.accumulatedText, 'slack'), MAX_MESSAGE_LENGTH),
    }),
    callbacks,
    startTime,
    true,
  );
}
```

### Step 4: Update handleError for buffered mode

Update `handleError` similarly -- when `existing.messageTs` is empty, post via `chat.postMessage`:

```typescript
async function handleError(
  channelId: string,
  errorMsg: string,
  threadTs: string | undefined,
  client: WebClient,
  streamState: Map<string, ActiveStream>,
  callbacks: AdapterOutboundCallbacks,
  startTime: number,
): Promise<DeliveryResult> {
  const key = streamKey(channelId, threadTs);
  const existing = streamState.get(key);
  streamState.delete(key);

  if (existing) {
    const finalText = truncateText(
      `${formatForPlatform(existing.accumulatedText, 'slack')}\n\n[Error: ${errorMsg}]`,
      MAX_MESSAGE_LENGTH,
    );

    // Buffered mode: post as new message
    if (!existing.messageTs) {
      return wrapSlackCall(
        () => client.chat.postMessage({
          channel: channelId,
          text: finalText,
          ...(threadTs ? { thread_ts: threadTs } : {}),
        }),
        callbacks,
        startTime,
        true,
      );
    }

    // Streaming mode: update existing message
    return wrapSlackCall(
      () => client.chat.update({
        channel: channelId,
        ts: existing.messageTs,
        text: finalText,
      }),
      callbacks,
      startTime,
      true,
    );
  }

  // No active stream -- standalone error
  const text = truncateText(`[Error: ${errorMsg}]`, MAX_MESSAGE_LENGTH);
  return wrapSlackCall(
    () => client.chat.postMessage({
      channel: channelId,
      text,
      ...(threadTs ? { thread_ts: threadTs } : {}),
    }),
    callbacks,
    startTime,
    true,
  );
}
```

